from flask import Flask, request, redirect, session, url_for
import requests
from urllib.parse import urlencode

app = Flask(__name__)
app.secret_key = 'your_secret_key'

# Client configuration
CLIENT_ID = 'your_client_id'
CLIENT_SECRET = 'your_client_secret'
AUTHORIZATION_URL = 'https://provider.com/oauth/authorize'
TOKEN_URL = 'https://provider.com/oauth/token'
REDIRECT_URI = 'https://yourapp.com/callback'
DOMAIN = 'yourapp.com'

@app.route('/')
def home():
    return 'Welcome to the OAuth 2.0 Client Application!'

@app.route('/login')
def login():
    redirect_uri = request.args.get('redirect_uri', REDIRECT_URI)

    if DOMAIN not in redirect_uri:
        return 'Invalid redirect_uri', 400

    auth_url = f"{AUTHORIZATION_URL}?{urlencode({
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': redirect_uri,
    })}"
    return redirect(auth_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    redirect_uri = request.args.get('redirect_uri', REDIRECT_URI)

    if DOMAIN not in redirect_uri:
        return 'Invalid redirect_uri', 400

    response = requests.post(TOKEN_URL, data={
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': redirect_uri,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET,
    })

    if response.status_code != 200:
        return 'Failed to retrieve access token', 400

    session['token'] = response.json().get('access_token')
    return 'Authorization successful!'

